	}

	return nil
}

func propagateCorrelationID(req *http.Request) {
	if correlationID := logging.CorrelationIDFromContext(req.Context()); correlationID != "" {
		req.Header.Set(httpx.HeaderCorrelationID, correlationID)
	}
